        assert_eq!(m.read_physical_u8(0x485), 16);
        assert_eq!(m.read_physical_u16(0x485), 16);
        assert_eq!(m.read_physical_u8(0x489) & 0x01, 0x01);

        m.cpu.registers.set_eax(0x0100);
