            assert_eq!(bus.read_io(0x3D5, BusWidth::Byte).unwrap(), 0xFF);

            bus.write_io(0x3D4, BusWidth::Byte, 0x0E).unwrap();
            bus.write_io(0x3D5, BusWidth::Byte, 0x12).unwrap();
            assert_eq!(bus.read_io(0x3D5, BusWidth::Byte).unwrap(), 0x12);
